#define CUDA_CHECK(call)                                                    \
    do {                                                                    \
        cudaError_t _e = (call);                                            \
        if (_e != cudaSuccess) {                                            \
            fprintf(stderr, "CUDA error %s:%d  %s\n",                      \
                    __FILE__, __LINE__, cudaGetErrorString(_e));            \
            exit(EXIT_FAILURE);                                             \
        }                                                                   \
    } while (0)

enum KernelID {
    K_COALESCED_ADD = 0,
    K_STRIDED_ADD = 1,
    K_DIVERGENT_ADD = 2,
    K_DIVERGENT_COMPUTE = 3,
    K_COMPUTE_REF = 4,
    K_TILED_TRANSPOSE = 5,
    K_ATOMIC_HISTOGRAM = 6,
    K_WARP_REDUCE_SHUFFLE = 7,
    K_LARGE_SMEM_STENCIL = 8,
    K_TINY_BLOCK_SAXPY = 9,
    K_FLOAT4_COPY = 10,
    K_RACE_SMEM_REDUCE = 11,
};

static void launch_once(KernelID kid,
                        const float* d_a, const float* d_b, float* d_c,
                        int n, int stride, int iters,
                        int grid, int grid2, int block)
{
    switch (kid) {
    case K_COALESCED_ADD:
        coalesced_add<<<grid, block>>>(d_a, d_b, d_c, n);
        break;
    case K_STRIDED_ADD:
        strided_add<<<grid2, block>>>(d_a, d_b, d_c, n, stride);
        break;
    case K_DIVERGENT_ADD:
        divergent_add<<<grid, block>>>(d_a, d_b, d_c, n);
        break;
    case K_DIVERGENT_COMPUTE:
        divergent_compute<<<grid, block>>>(d_a, d_c, n, iters);
        break;
    case K_COMPUTE_REF:
        compute_ref<<<grid, block>>>(d_a, d_c, n, iters);
        break;
    case K_TILED_TRANSPOSE:
        { dim3 _g(128, 128); dim3 _b(32, 32); tiled_transpose<<<_g, _b>>>(d_a, d_c, n); }
        break;
    case K_ATOMIC_HISTOGRAM:
        atomic_histogram<<<((n + 256 - 1) / 256), block>>>(d_a, d_c, n);
        break;
    case K_WARP_REDUCE_SHUFFLE:
        warp_reduce_shuffle<<<((n + 256 - 1) / 256), block>>>(d_a, d_c, n);
        break;
    case K_LARGE_SMEM_STENCIL:
        large_smem_stencil<<<((n + 256 - 1) / 256), block>>>(d_a, d_c, n);
        break;
    case K_TINY_BLOCK_SAXPY:
        tiny_block_saxpy<<<((n + 32 - 1) / 32), block>>>(d_a, d_b, d_c, n);
        break;
    case K_FLOAT4_COPY:
        float4_copy<<<((n + 256 - 1) / 256), block>>>(d_a, d_c, n);
        break;
    case K_RACE_SMEM_REDUCE:
        race_smem_reduce<<<((n + 256 - 1) / 256), block>>>(d_a, d_c, n);
        break;
    default: break;
    }
}

static float* time_kernel(KernelID kid,
                           const float* d_a, const float* d_b, float* d_c,
                           int n, int stride, int iters,
                           int grid, int grid2, int block,
                           int warmup, int runs)
{
    cudaEvent_t start, stop;
    CUDA_CHECK(cudaEventCreate(&start));
    CUDA_CHECK(cudaEventCreate(&stop));
    for (int i = 0; i < warmup; ++i)
        launch_once(kid, d_a, d_b, d_c, n, stride, iters, grid, grid2, block);
    CUDA_CHECK(cudaDeviceSynchronize());
    float* times = new float[runs];
    for (int i = 0; i < runs; ++i) {
        CUDA_CHECK(cudaEventRecord(start));
        launch_once(kid, d_a, d_b, d_c, n, stride, iters, grid, grid2, block);
        CUDA_CHECK(cudaEventRecord(stop));
        CUDA_CHECK(cudaEventSynchronize(stop));
        CUDA_CHECK(cudaEventElapsedTime(&times[i], start, stop));
    }
    CUDA_CHECK(cudaEventDestroy(start));
    CUDA_CHECK(cudaEventDestroy(stop));
    return times;
}

static void compute_stats(const float* arr, int n,
                           double* mean_out, double* std_out)
{
    double sum = 0.0;
    for (int i = 0; i < n; ++i) sum += arr[i];
    double mean = sum / n;
    double var  = 0.0;
    for (int i = 0; i < n; ++i) { double d = arr[i] - mean; var += d * d; }
    *mean_out = mean;
    *std_out  = (n > 1) ? sqrt(var / (n - 1)) : 0.0;
}

